var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`미지는 두렵지 않다.`,JPN:`未知は怖くない。`,ENG:`I do not fear the unknown.`,TWN:`未知並不可怕。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`정착을 두려워하는 이방인이 그렇듯, 그저 무지에 안주하는 삶이 두려울 뿐.`,JPN:`定着を恐れる異邦人がそうであるように、ただ無知に甘んじる人生が怖いだけ。`,ENG:`I am as afraid of living in ignorance as a stranger is of settling down.`,TWN:`就像害怕定居的外邦人一樣，我只是害怕安於無知的生活。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`어린 시절부터, 줄곧 그러하였으니.`,JPN:`幼い頃から、ずっとそうだった。`,ENG:`It has always been like that, ever since childhood.`,TWN:`從小到大，我一向如此。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`으으, 무거워라…….`,JPN:`うう、おもたい……`,ENG:`Oof, it's so heavy...!`,TWN:`呃，好重呀……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`좋아. 이렇게 커다란 의자를 딛고 올라가면 책장 꼭대기도 문제없겠지?`,JPN:`よし。これだけ大きい椅子の上にあがれば、本棚のてっぺんだって手が届きますわよね？`,ENG:`Okay, I should be able to reach the top of the bookcase with a chair this tall, right?`,TWN:`好啦。踩到這麼大的椅子上，應該能夠到書架頂上吧？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`영~차!`,JPN:`よ～いしょっ！`,ENG:`Hup!`,TWN:`嘿～咻！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`역시 난 똑똑해. 에밀리가 과자 꺼내 먹던 방법을 이럴 때 쓰다니.`,JPN:`私ったらなんて賢いんでしょう。エミリーがお菓子をつまみ食いするときの方法をこういう時に利用するなんて。`,ENG:`I'm so smart! No one would've thought to use Emliy's cookie stealing tricks like this!`,TWN:`我果然很聰明。竟然把艾米麗偷吃餅乾的方法用在這種時候。`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`어른이 되면 염소 가죽 벗기는 일도 어머님보다 더 잘하지 않을까? 흐흠.`,JPN:`大人になったら、ヤギの皮を剥ぐのもお母様よりうまくやれるんじゃないかしら？　ふふん。`,ENG:`Maybe I'll even be better at skinning goats than Mother when I'm older. Hehe.`,TWN:`等我再長大點，剝羊皮的工作應該會做得比媽媽還好吧？呵呵。`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`아차. 이럴 때가 아니지. 늦장 부리다 들키면 어머님께 혼날 거야.`,JPN:`まあ。こうしている場合ではありませんわ。もたもたしてバレでもしたらお母様に怒られてしまいます。`,ENG:`Oh, right! I should hurry if I don't want Mother scolding me again...`,TWN:`哎呀，現在不是胡思亂想的時候。再磨蹭下去會被媽媽發現狠狠教訓的。`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`어디 보자. 이 책은…….`,JPN:`えっと。この本は……`,ENG:`Let’s see here... This book is about...`,TWN:`讓我看看，這本書……`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`두통을 일으키는 저주, 사람을 벌레로 만드는 저주, 가뭄을 부르는 저주…….`,JPN:`頭痛を起こす呪い、人を虫に変える呪い、干ばつを起こす呪い……`,ENG:`A curse causing headache, a curse turning people into insects, a curse summoning a famine...`,TWN:`引起頭痛的詛咒，把人變成蟲子的詛咒，召喚乾旱的詛咒……`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`저주, 저주, 저주…….`,JPN:`呪い、呪い、呪い……`,ENG:`Curse, curse, curse...`,TWN:`詛咒、詛咒、詛咒……`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`에이, 이게 뭐야. 표지만 예쁘지 순 나쁜 책이네.`,JPN:`もう、何ですの。表紙がきれいなだけで悪いことしか書いてないじゃない。`,ENG:`What's all this? All these books have pretty covers but are about curses.`,TWN:`什麼嘛。封面那麼好看，原來是一本很糟糕的書呢。`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`이 책은 어떨까? 제목이… 시시… 시식… 교전이…?`,JPN:`この本はどうかしら？　タイトルが……しし……ししょく……きょうてんぎ……？`,ENG:`What about this one? The title is... "Coolt"...? "Cultes des Goules"?`,TWN:`這本書怎麼樣？標題是……屍屍……屍食……教典儀……？`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`narration`,speaker:null,text:{KOREA:`<color=#ff3636>주술을 배우고 싶니?</color>`,JPN:`<color=#ff3636>呪術を教わりたい？</color>`,ENG:`<color=#ff3636>Do you want to learn sorcery?</color>`,TWN:`<color=#ff3636>你想學咒術嗎？</color>`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`응……?`,JPN:`え……？`,ENG:`Hmm...?`,TWN:`嗯……？`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_GIRL`,text:{KOREA:`누구세요? 어디에 계신 거예요?`,JPN:`どなたですの？　どこにいらっしゃるの？`,ENG:`Who're you? Where are you?`,TWN:`你是誰？你在哪？`},stage:{bg:`ESPR2_04`,slots:{L:null,C:null,R:null}}}];export{e as default};